import anthropic
import time

client = anthropic.Anthropic(max_retries=0)  # Disable SDK retries

def call_claude_with_rate_limit_handling(prompt):
    try:
        return client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            messages=[{"role": "user", "content": prompt}],
        )
    except anthropic.RateLimitError as e:
        # Get retry-after from headers
        retry_after = getattr(e, "retry_after", None)

        if retry_after:
            print(f"Rate limited. Waiting {retry_after} seconds...")
            time.sleep(retry_after)  # Honor server's guidance
        else:
            # Fallback to exponential backoff
            time.sleep(10)  # Default wait

        # Retry once
        return client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            messages=[{"role": "user", "content": prompt}],
        )

